sys_transform_map.script:
(function transformRow(source, target, map, log, isUpdate) {

    //Associate or add a Company record for the Account
    var accountUtilsSI = new EQIX_AccountContact_Util();
    if (source.u_org_id != "") {
        target.parent = accountUtilsSI.getCompany(source.u_org_id, source.u_org_name);
    }
    //EPE2-460
	//nullify parent 
    if (gs.nil(source.u_org_id) && !(gs.nil(target.u_org_id)) && gs.nil(source.u_org_name) && !(gs.nil(target.u_org_name))) {
        target.parent = "";
    }
    //nullify city 
    if (gs.nil(source.u_city) && !(gs.nil(target.city))) {
        target.city = "";
    }
    //nullify street
    if (gs.nil(source.u_street) && !(gs.nil(target.street))) {
        target.street = "";
    }
    //nullify phone
    if (gs.nil(source.u_phone) && !(gs.nil(target.phone))) {
        target.phone = "";
    }
    //nullify zip
    if (gs.nil(source.u_zip) && !(gs.nil(target.zip))) {
        target.zip = "";
    }
    //nullify u_org_id
    if (gs.nil(source.u_org_id) && !(gs.nil(target.u_org_id))) {
        target.u_org_id = "";
    }
    //nullify u_org_name
    if (gs.nil(source.u_org_name) && !(gs.nil(target.u_org_name))) {
        target.u_org_name = "";
    }
    //nullify state
    if (gs.nil(source.u_state) && !(gs.nil(target.state))) {
        target.state = "";
    }
    //nullify u_address_line_3
    if (gs.nil(source.u_address_line_3) && !(gs.nil(target.u_address_line_3))) {
        target.u_address_line_3 = "";
    }
    //nullify u_address_line_2
    if (gs.nil(source.u_address_line_2) && !(gs.nil(target.u_address_line_2))) {
        target.u_address_line_2 = "";
    }
    //nullify u_partner_type
    if (gs.nil(source.u_partner_type) && !(gs.nil(target.u_partner_type))) {
        target.u_partner_type = "";
    }



})(source, target, map, log, action === "update");
